INSERT INTO public.books (id, title, author, translator, description, cover, price_egp, price_usd, category_slug, additional_categories, is_best_seller, is_featured, rating, pages, year) VALUES
  ('1', 'امرأة ڤولاذية', 'نهار أحمد', NULL, 'تدور أحداث الرواية عن فتاة خلقت بقوة خارقة للطبيعة؛ مثل السحر، ولكن حتى تستطيع السيطرة على قواها الداخلية، كان عليها الإنضمام لأكبر فريق ملاكمة عالمي، لتكتشف أن المدربة الخاصة بها كانت صديقة والدتها المقربة، وأنها تمتلك نفس قوة الفتاة ووالدتها، وحتى تستطيع فعل ذلك؛ كان عليها التنقل بالزمن؛ ما بين الماضي والمستقبل، وأثناء عودتها بالماضي شاهدت مقتل والدتها، ولتغيير هذا العالم، عن طريق الإختيار ما بين جانب الخير والشر، فماذا اختارت؟', 'https://i.ibb.co/Xff2Mdbs/Whats-App-Image-2026-04-10-at-6-57-31-PM.jpg', 150, 10, 'crime-action', ARRAY['sci-fi-history']::text[], true, true, 4.7, 150, 2025),
  ('2', 'الماركتير', 'د. الحسن العزاوي', NULL, 'هل سألت نفسك يوماً لماذا يدفع البعض أضعافاً مضاعفة في منتج قد يقوم بنفس الوظيفة؟ لماذا نشتري قهوة بعشرة جنيهات وأخرى بمائة… ساعة عادية وساعة فاخرة… خدمة متاحة وأخرى غالية ومع ذلك نُقبل عليها بشغف؟! هذا الكتاب ليس عن التسويق كإعلانات وشعارات بل عن القيمة: كيف تُصنع كيف تُقدَّم وكيف تُقاس؟ ستجد بين صفحاته قصصاً واقعية أفكاراً عملية وآراء لخبراء وفلاسفة تكشف لك أن العميل لا يشتري المنتج… بل يشتري التجربة القصة والمعنى.', 'https://i.ibb.co/tTLpwCzQ/Whats-App-Image-2026-04-10-at-6-37-36-PM.jpg', 250, 10, 'self-help-psychology', '{}'::text[], true, true, 4.8, 342, 2025),
  ('3', 'خطوات طريق السعادة', 'لينا عبدالخالق', NULL, 'هل تبحث عن السعادة؟ كلنا، وبدون أي أستثناء، نبحث عن السعادة، فهي حق مشروع لكل انسان وهي من أهم أهدافه الرئيسية لتمنحه الشعور بالسرور والارتياح والرضا وتساعده على مواجهة صعوبات وضغوطات الحياة اليومية. يقدم هذا الكتاب خطوات فعالة ومجربة يمكننا بإتباعها أن نصبح أكثر سعادة ولتحسين نوعية الحياة التي تؤثر إيجابا على مختلف جوانب حياة الانسان الشخصية والعملية ورفع انتاجيته والإبداع.', 'https://i.ibb.co/4wj6bxqt/image.png', 200, 8, 'self-help-psychology', '{}'::text[], true, true, 4.6, 144, 2025),
  ('4', 'كلهم أنا', 'ماجد مدحت', NULL, '"كلهم أنا" .. مش مجرد صفحات، دا مراية. مراية لكل واحد فينا جواه أكتر من حد.. حد بيضحك وهو موجوع، وحد بيكمل وهو مكسور، وحد لسه بيدور على نفسه وسط الزحمة. مجموعة قصصية بتشدك من أول قصة، وتعيشك مشاعر مختلفة.. خسارة، حب، فقد، صدفة، ألم، وأمل خافت بين السطور.', 'https://i.ibb.co/spTD1gks/Whats-App-Image-2026-04-10-at-5-59-34-PM.jpg', 150, 7, 'drama-romance', '{}'::text[], true, true, 4.5, 168, 2025),
  ('59', 'هو أنا؟', 'يوسف ابو العلا', NULL, 'رواية نفسية عن رجل يبدأ في فقدان ثقته في إدراكه للواقع، حين تتحول نوتته الشخصية إلى مساحة تكتب ما لم يفكر فيه بعد، وتصبح المرآة كيانًا يسبقه في الحركة والقرار.

رحلة داخل عقل يتصدّع ببطء…

حيث يصبح الشك هو الحقيقة الوحيدة،

ويتحوّل الوعي من ملاذ آمن… إلى ساحة صراع.

عمل يطرح سؤالًا فلسفيًا مربكًا:

هل الإنسان يتحكّم في وعيه… أم أن وعيه هو من يقرّر من يكون؟

رواية لا تمنح تفسيرًا واحدًا،

بل تترك القارئ يواجه نفسه… ويخرج بفهمه الخاص', 'https://i.ibb.co/k6sxS7Q8/image.png', 160, 10, 'mystery-horror', ARRAY['crime-action']::text[], true, false, 4.7, 188, 2025),
  ('5', 'الشقة المهجورة', 'كمال الهواري', NULL, 'تدور أحداث الرواية داخل شقة غامضة في حي شعبي بالقاهرة، قريبة من المقابر، حيث تبدأ أصوات وظلال وأسرار قديمة في الظهور، لتقود الشخصيات — والقراء — إلى مواجهة عالم خفي يتقاطع مع الواقع دون أن يُرى. الرواية تقدم معالجة سردية لعالم الجن وتأثيره على البشر في إطار درامي مشوق، وتطرح تساؤلات حول الحدود الفاصلة بين الوهم والحقيقة، والخوف والإيمان.', 'https://i.ibb.co/0jtk4Ddd/image.png', 150, 7, 'mystery-horror', '{}'::text[], true, false, 4.6, 182, 2025),
  ('6', 'مغامرات أرجينت', 'كيرلس أشرف', NULL, 'رواية مغامرات وتشويق تنقلك لعالم مختلف تماما عن ما عاهدته.. فيها الفضول كان شرارة كل شيء، وكان أيضًا اللعنة التي بدأت كل هذا. جو وليلي صديقان يقودهما الفضول إلى مواجهة كائناتٍ قديمة؛ يكتشفان أن الهروب بلا جدوى وأنهما محاصران. مفاجآت في انتظارهم عند كل منعطف… ولن يكون هناك وقتٌ للراحة.', 'https://i.ibb.co/JwKRL8St/image.png', 120, 7, 'crime-action', ARRAY['sci-fi-history','drama-romance']::text[], true, false, 4.5, 141, 2025),
  ('7', 'الكتاب الأسود', 'أحمد منصور', NULL, 'الكتاب الأسود ليس مجرد رواية، بل لعنة تبدأ منذ الصفحة الأولى، تشعر معها أن الكلمات كُتبت خصيصًا لك. رحلة تقودك للذهاب بقلبٍ والعودة بآخر، بعد أن يتغير شيء داخلك إلى الأبد. هي رواية الفضول؛ ذلك الدافع الذي يجرك للقراءة رغم الخوف والغموض. لعبة نفسية عميقة تجبرك على مواجهة مخاوفك ورغباتك الخفية.', 'https://i.ibb.co/DP5qkxwj/image.png', 150, 7, 'mystery-horror', '{}'::text[], true, false, 4.7, 188, 2025),
  ('8', 'حكاية شمسية', 'حاتم حيدر', NULL, 'في المصيف، الشمسية مش بتضلل على الناس بس، دي شاهدة عليهم و بتحفظ أسرارهم، وتخزن حكاياتهم في قماشها، وتُسلّمها للموج وياخدها البحر بعيدً، عشان يحكيها لناس على شواطئ وبلاجات تانية سواء في الساحل القديم او الجديد. وكل شمسية ليها حكاية وبتختلف الحكايات من شاطيء للتاني.', 'https://i.ibb.co/RG3mZYCm/image.png', 120, 7, 'drama-romance', '{}'::text[], true, false, 4.4, 134, 2025),
  ('9', 'القلوب المليانة', 'د. منال شرف الدين', NULL, 'يضم العمل خمس عشرة قصة مستوحاة من الواقع الإنساني والاجتماعي لنساء عانين من السمنة المفرطة، حيث يتجاوز الكتاب البعد الصحي ليغوص في الطبقات الأعمق من التجربة النسوية، كاشفًا ما وراء الكيلوجرامات الزائدة من مشاعر وأوجاع وصراعات داخلية. ترصد القصص علاقة الجسد بالروح، والوزن بالوجدان.', 'https://i.ibb.co/B238tqjR/image.png', 100, 7, 'drama-romance', '{}'::text[], true, false, 4.5, 100, 2025),
  ('10', 'عودة الرسول', 'خالد أحمد', NULL, 'كتاب نبحث فيه أزلية القرآن المسطور باعتباره دليل الخالق الي العقل البشري ليكشف الله لعقولنا كل من القرآن المكنون والقرآن المنشور. بحث بدون حدود وبدون موانع عقلية نبحث فيه كل كلمة تخص الرسول والنبي محمد ومن معه من الرسل والأنبياء بحث نطهر فيه عقلا وقلبا من كل الموروث الديني. بحث نري فيه النص القرآني بلسان عربي مبين لا نحفل في هذا البحث باللغة أو التاريخ أو قيد الزمان والمكان والأشخاص الحرف القرآني نراه أية حرة اية كاملة تعطيك المفتاح لكي تدخل الي عالم واسع وعميق من الأسرار الربانية ومن داخل الكلمة نصل الي جذرها.', 'https://i.ibb.co/rK4Wht01/image.png', 200, 10, 'self-help-psychology', ARRAY['religious']::text[], false, false, 4.5, 234, 2025),
  ('11', 'ملاذ Refuge', 'حسناء معتز "العنقاء"', NULL, 'الكتاب باللغة العربية الفصحى واللغة الإنجليزية. يتناول هذا الكتاب أهمية المرض النفسي، وأعراضه، وكيفية ظهوره، ولماذا يحدث، وما أسبابه وآثاره على الفرد والمجتمع. كما يستعرض معظم أقسام الاضطرابات النفسية، مع إلقاء الضوء على الجوانب المرتبطة بالمرأة، وأسس دراسة الطب النفسي، وأهمية الوعي بالأعراض النفسية وطرق فهمها.', 'https://i.ibb.co/YBvKh31F/image.png', 200, 10, 'self-help-psychology', '{}'::text[], false, false, 4.5, 203, 2025),
  ('12', 'القيادة الوهمية', 'د. سحر سعيد', NULL, 'في عالمنا الحديث، تُوزَّع الألقاب بسهولة. "قائد"، "مدير"، "رئيس"، "ملهم"، كلمات براقة تُمنح أحياناً دون محتوى حقيقي. هذا الكتاب ليس دليلاً تقليدياً عن القيادة، بل هو رحلة لرفع الغطاء عن أقنعة كثيرة. سنكشف كيف تُصنع صورة القائد في بعض الأحيان بعيداً عن جوهر القيادة، ولماذا ننجذب أحياناً إلى الكاريزما الفارغة أكثر من القيم الحقيقية.', 'https://i.ibb.co/vvjrPJLC/image.png', 150, 10, 'self-help-psychology', '{}'::text[], false, false, 4.5, 158, 2025),
  ('13', 'أعراض المرض النفسي', 'د. بسمة جبريل', 'شهد مجدي', 'يتناول هذا الكتاب أهمية المرض النفسي، وأعراضه، وكيفية ظهوره، ولماذا يحدث، وما أسبابه وآثاره على الفرد والمجتمع. كما يستعرض معظم أقسام الاضطرابات النفسية، مع إلقاء الضوء على الجوانب المرتبطة بالمرأة، وأسس دراسة الطب النفسي، وأهمية الوعي بالأعراض النفسية وطرق فهمها. الكتاب باللغة العربية الفصحى واللغة الإنجليزية.', 'https://i.ibb.co/mVq6crtj/image.png', 100, 7, 'self-help-psychology', '{}'::text[], false, false, 4.4, 66, 2025),
  ('14', 'منهجنا', 'د. الديڤا', NULL, 'الضغوطات التي تكسرنا، هي نفسها التي تصنع منا ألماسًا، فالفحم الذي يتعرض لضغوط هائلة يتحول إلى جوهرة ثمينة. هكذا هي الحياة، حيث تتحول التحديات إلى فرص للنمو والتحول. فكن أنت النجم الذي يلمع في سماء الحياة، واترك وراءك أثرًا لا يمحى، وقلبًا لا ينسى، وروحًا لا تموت. "ثلاثون خطوة للنجاح"', 'https://i.ibb.co/CR1kjcC/image.png', 200, 10, 'self-help-psychology', '{}'::text[], false, false, 4.4, 263, 2025),
  ('15', 'لسه في امل', 'مريم ياسر', NULL, 'خواطر وجدانية تلامس القلب وتعبّر عن لحظات ضعف وقوة، ألم وأمل. كُتبت بإحساس صادق، وكأنها رسالة موجهة لكل شخص مر بلحظة تعب وحاسس إنه لوحده. الكتاب بيحمل طاقة دفئ وتشجيع، ويدّي القارئ إحساس إن في حد فاهمه وحاسس بيه. مش بيأكد إن الحياة سهلة، لكنه بيأكد إن دايمًا في نقطة نور حتى لو الدنيا ضلمت.', 'https://i.ibb.co/FLFHJK4X/image.png', 100, 7, 'self-help-psychology', '{}'::text[], false, false, 4.4, 100, 2025),
  ('16', 'المنظومة', 'محمد ممدوح', NULL, 'فى قلب عالم يختلط فيه المال بالدم، والفساد بالخوف يقف خالد حبيب شاب كاد يفقد كل شئ بعد حادث مأساوى تركه على كرسى متحرك. ينفى خالد إلى مزرعة نائية حيث يلتقى بجلال رجل حكيم يعيد تشكيله من الداخل، ويزرع فيه بذور المعرفة والقوة. بعد سنوات من العزلة والتدريب النفسى والفكرى يعود خالد أقوى مما كان ليس فقط لينهض على قدميه بل ليؤسس منظومة استخبارات سرية داخل شركات والده.', 'https://i.ibb.co/5XWvg487/image.png', 100, 8, 'sci-fi-history', ARRAY['crime-action']::text[], false, false, 4.4, 106, 2025),
  ('17', 'ألوان من السعودية', 'حمدي جاد', NULL, 'حب المملكة العربية السعودية وأهلها فى القلب وهذا سرد من ألوان وزهور السعودية لما فى قلبي ومشوار التجارة فى السعودية والتعرف على بعض أنواع التجارة والمكاسب المالية المحتملة. قصص لبعض الأشخاص والعائلات لما مرو به من تضحيات وأزمات.', 'https://i.ibb.co/LzhKJzSB/image.png', 100, 7, 'drama-romance', '{}'::text[], false, false, 4.3, 86, 2025),
  ('18', 'أنا الطيب وأنا الشرير', 'عمر عبداللاه', NULL, 'تحكي عن رحلة بين الخير والشر، التنقل بين الكنائس المهجورة، وغرف المناظرات. الموضوع مكنش معركة سيوف ولا دم، إنما مناظرات وحوارات عن معنى العبادة، الشر والمعاناة، والتفاوت بين البشر. مصطفى اللي كان متدين في الأول اتسحب لشبهات الفلسفات الغربية وبدأ يهاجم الدين، لكنه كان من جوه عايش فراغ كبير. رجع مصطفى للمسجد والدموع في عينه، واعترف قدام الكل إنه أخطأ، وأعلن توبته.', 'https://i.ibb.co/Kc8VGjRm/image.png', 160, 10, 'religious', ARRAY['self-help-psychology']::text[], false, false, 4.5, 216, 2025),
  ('19', 'سِكشَن', 'نجلاء عبدربه', NULL, 'تَمُرَّ مَرْحَلَةَ اَلثَّانَوِيَّةِ اَلْأَشْبَهِ بِجِسْرِ بَيْنَ اَلطُّفُولَةِ وَالنُّضْجِ. يَمْضِي كُلُّ طَالِبٍ فِي رِحْلَتِهِ اَلْخَاصَّةِ، وَمَعَ نِهَايَةِ اَلطَّرِيقِ، يُدْرِكَ اَلْجَمِيعُ أَنَّ اَلْجَامِعَةَ لَمْ تَكُنْ مُجَرَّدَ دِرَاسَةٍ… بَلْ كَانَتْ اَلْحِكَايَةُ اَلَّتِي صَنَعَتْ جُزْءًا مِنْهُمْ، وَتَرَكَتْ فِي اَلْقَلْبِ ذِكْرَيَاتٍ لَا تَنْطَفِئُ.', 'https://i.ibb.co/CpM64z66/image.png', 100, 7, 'drama-romance', '{}'::text[], false, false, 4.3, 68, 2025),
  ('20', 'كوكب الحياة الإيجابية "الجزء الأول"', 'خلود خضري', NULL, 'الكتاب ده للتطوير الذاتي، لو عايز تعيش عالمك الخاص بشكل منظم ومليان تفاؤل أو لو عايز تعرف كل تفصيلة في حياتنا من مشاكل خطيرة، قصص تحفيزية، حكاوي دينية، حكايات إنسانية. يبقى تقرأ الكتاب دة على مهلك وبلاش تحكم عليه بسرعة. هذا الكتاب سيكون أكيد مرجع حياتك السرى بس هات الجزئين منه لانهم مرتبطين ببعض.', 'https://i.ibb.co/tw25npsP/image.png', 200, 7, 'self-help-psychology', '{}'::text[], false, false, 4.5, 432, 2025),
  ('21', 'كوكب الحياة الإيجابية "الجزء الثاني"', 'خلود خضري', NULL, 'الجزء الثاني من كتاب التطوير الذاتي، لو عايز تعيش عالمك الخاص بشكل منظم ومليان تفاؤل أو لو عايز تعرف كل تفصيلة في حياتنا من مشاكل خطيرة، قصص تحفيزية، حكاوي دينية، حكايات إنسانية. هذا الكتاب سيكون أكيد مرجع حياتك السرى بس هات الجزئين منه لانهم مرتبطين ببعض.', 'https://i.ibb.co/fzXZL7dy/image.png', 200, 7, 'self-help-psychology', '{}'::text[], false, false, 4.5, 420, 2025),
  ('22', 'أنا أستحق', 'فاطمة عبدالعزيز', NULL, 'مش مجرد سيرة ذاتية… دي رحلة حقيقية لامرأة واجهت الانكسار، وتعلمت تختار نفسها وتبني حياة أصدق وتربي ابنها بوعي من غير جلد ذات. كتاب عن التغيير من الداخل عن الاستحقاق عن إنك تعيشي على مقاسك مش على توقعات غيرك. «أنا أستحق»… لأنك مش محتاجة إذن علشان تبدأي من جديد.', 'https://i.ibb.co/MxJ3Fy7v/image.png', 100, 7, 'self-help-psychology', '{}'::text[], false, false, 4.4, 91, 2025),
  ('23', 'شيزوفرينيا النجاح', 'عبدالرحمن بهجات', NULL, 'أيها المتعبُ الذي أنهكتْه العزلةُ ونالَ منه اليأسُ ما نال، الطريقُ أمامك، والوقتُ معك لتصنعَ المجدَ وتحققَ النجاح، فقط امنحْ نفسكَ فرصةً للتعبيرِ عنك، عن آمالكَ وطموحاتِك التي وضعتَها بيديك تحتَ ركامِ الإحباطِ والفشل. هوِّنْ على نفسِك، فالأمرُ أبسطُ مما تتخيل.', 'https://i.ibb.co/v6rpZrnP/image.png', 120, 7, 'self-help-psychology', '{}'::text[], false, false, 4.4, 106, 2025),
  ('24', 'الدليل التطبيقي للتهيئة المهنية', 'د. ياسين هديب', NULL, 'ازدادت خلال العقود الأخيرة نسبة الأطفال الذين يتم تشخيص حالاتهم الإصابة باضطراب طيف التوحد. تمر مرحلة التأهيل المهني بحلقات ثلاث متصلة وهي: التهيئة المهنية وهي أولى الحلقات وأطولها وأهمها تليها حلقة التدريب المهني وأخيرا حلقة التشغيل المهني والمتابعة. هذا الدليل التطبيقي هو الحل لممارسة التهيئة المهنية على أسس علمية.', 'https://i.ibb.co/nGddrWz/image.png', 250, 12, 'self-help-psychology', '{}'::text[], false, false, 4.5, 251, 2025),
  ('25', 'حواديت عمو طارق', 'طارق فاروق', NULL, 'حينما يمر الانسان بمواقف كثيرة في حياته، وتكون هذه المواقف مؤثرة على بعضها البعض مواقف تسرك وتسعد قلبك، وبمرور الوقت تصبح هذه المواقف هي سبب حزنك وهمك. وبعد ان تعيش كل هذه المواقف تجلس وحيدا تتذكر وتتعجب ويبداء عقلك في كتابة الاحداث، ولكن تتدخل ويثبت في عقلك انه مهما طال الظلام ومهما عشت من احداث مأساوية سيجئ يوم النور.', 'https://i.ibb.co/mVZLKcdr/image.png', 100, 7, 'self-help-psychology', '{}'::text[], false, false, 4.3, 80, 2025),
  ('26', 'الماريستان', 'أمير عبدالغفار', NULL, 'تحكي عن طبيب نفسي أربعيني ساخط علي الحياة إلي حد كبير بسبب ما تعرض له من معاناة، وهو ما دفعه للهروب من الواقع إلي عوالم أخري ممزوجة بقدر بسيط من الكوميديا بجانب قصة حب قد تكون غير متكافئة.', 'https://i.ibb.co/4ZpCZJTz/image.png', 120, 8, 'drama-romance', ARRAY['self-help-psychology']::text[], false, false, 4.4, 126, 2025),
  ('27', 'ديوان أَسْمَعْتِني صَمْتًا', 'د. حسين صبري', NULL, 'ديوان شعري بالعربية الفصحى تتنوع قصائده بين الشعر العمودي التقليدي وشعر التفعيلة، وتتوزع معزوفاته الشعرية بين أغراض الشعر العربي: في العشق، في الولاء، في التأمل، في الوجع، في القدوة، في الحكمة، في الفقد، في الوجد. ينظم قصائد هذا الديوان الحس الوطني مع الغزل والحكمة، جنباً إلى جنب وشعر الانتماء والقدوة.', 'https://i.ibb.co/cSNXqQgk/image.png', 220, 10, 'drama-romance', '{}'::text[], false, false, 4.5, 165, 2025),
  ('28', 'حبيبتي التي لم أرها بعد', 'د. يوسف احمد خلف', NULL, 'ليست هذه حكاية عاشق ينتظر حبيبته، بل حكاية إنسان ينتظر أن يرى نفسه. كل وجه حلم به، كل رسالة كتبها، كانت بحثاً عن الجزء المنسي منه. الغياب هنا ليس فقداناً، بل تجلٍ... والأنثى ليست شخصاً، بل سؤالاً. في كل سطر، ينكشف له أن ما يبحث عنه في الخارج، يسكن في داخله منذ البدء.', 'https://i.ibb.co/PGj35kfx/image.png', 150, 10, 'drama-romance', '{}'::text[], false, false, 4.5, 163, 2025),
  ('29', 'رحلة أناروز وتوسمان', 'ندا احمد "زهرة الهالڤيتي"', NULL, 'في عالمٍ يتقاطع فيه السحر بالواقع، تبدأ رحلة توسمان وأناروز… هي فتاة فقدت عائلتها، وهو ضابط يطارد ماضيه المظلم. زواج قسري بطقسٍ سحري، أسرار عائلية مدفونة، وحب يولد من رماد الألم. ممالك، وأميرات، ومصائر متشابكة… حرب بين قوى الخير والشر، وأميرة تُكتشف حقيقتها وسط كهف الأساطير.', 'https://i.ibb.co/7xNqLTwy/image.png', 100, 10, 'drama-romance', ARRAY['sci-fi-history']::text[], false, false, 4.5, 100, 2025),
  ('30', 'رحلة الألف ميل', 'د. فاطمة الرفاعي "آل عامر"', NULL, 'يقولون إن رحلة الألف ميل تبدأ بخطوة، لكنهم لا يخبرونك أن أولى الخطوات ليست على الأرض، بل في القلب. كنتُ قد خرجت من زلزالٍ هزّ عالمي الصغير — لم يكن زلزالًا جغرافيًا، بل نفسيًا. حينها قررت السفر — لا هربًا، بل بحثًا. ومن فيينا إلى القدس، قطعت المدن كما يقطع القلب دروبه في الشفاء.', 'https://i.ibb.co/Jw61cXSY/image.png', 120, 10, 'sci-fi-history', '{}'::text[], false, false, 4.5, 80, 2026),
  ('31', 'فتاة من الغرب ورجل من الشرق', 'صفاء الباز', NULL, 'تحكي عن طفلة صغيرة ذهبت للعيش مع رجل بعد وفاة زوجته لسبب مجهول لكن يشاء القدر وهذه الطفلة تتوفى لسبب ما وتُدفن دون علمه ولكن بعد مرور أعوام يتم إسترجاع "الذهب المفقود"...', 'https://i.ibb.co/GQsMFH8T/image.png', 100, 8, 'drama-romance', '{}'::text[], false, false, 4.4, 68, 2025),
  ('32', 'هروب واقعي', 'اسماء أحمد', NULL, 'هربت آسيا من حياة مظلمة تركت خلفها أسرارًا لا يجرؤ أحد على حملها… ولا حتى ابنتها الصغيرة شهد. ظنّت أن الشارع سيكون خلاصها، لكنه كان أشد قسوة مما هربت منه، حتى قادتها الصدفة إلى حياة جديدة يشاركها فيها شابان غامضان: لؤي وأمجد. هذه ليست قصة هروب… بل حكاية امرأة تُطاردها الحقيقة، وتحاصرها الأسرار.', 'https://i.ibb.co/8gqn80HW/image.png', 200, 10, 'drama-romance', '{}'::text[], false, false, 4.5, 323, 2025),
  ('33', 'لن أصلح الكون لكني سأحاول', 'اسماء أحمد', NULL, 'كان كل شيء ساكنًا… حتى ظهرت الأوراق. سطورٌ كتبها عرفات قبل أن يختفي بعشرين عامًا، تحمل اسمًا واحدًا: أسماء. وفي الجهة الأخرى من الحكاية، امرأة تخفي مرضًا وصوتًا لا يسمعه أحد. رحلتان للبحث… ولقاء واحد يعيد للحكاية نبضها، ويكشف أن بعض القلوب لا تنسى، وبعض الحكايات لا تموت… بل تنتظر من يعيد فتحها.', 'https://i.ibb.co/PvbS4bmC/image.png', 200, 10, 'drama-romance', ARRAY['self-help-psychology']::text[], false, false, 4.5, 258, 2025),
  ('34', 'بداخلي ضجيج من المشاعر', 'مجموعة مؤلفين', NULL, 'في هذا الكتاب، أفتح أبواب قلبي على مصراعيها، لأُخرج كل ما اختبأ بين الصمت والوجع، بين الفرح العابر والحزن المقيم. "بداخلي ضجيج من المشاعر" ليس مجرد خواطر، بل هو اعتراف صادق، ولحظات متفرقة من حياةٍ تفيض بالأحاسيس. ستجد بين صفحاته مزيجًا من الحب، الفقد، القوة، والحنين.', 'https://i.ibb.co/9mnvcL61/image.png', 100, 7, 'drama-romance', '{}'::text[], false, false, 4.4, 124, 2025),
  ('35', 'أشباح الشر', 'ليلى مدحت', NULL, 'الكتاب بيحكي عن مجموعة من القصص لكل قصة تحكي عن شخص بيعاني من شئ داخله حتى يرى ان مخاوفه تتحقق أمامه ليُضطر إلى مواجهتها مثل الجاثوم والأحلام التي تنتهي في الغالب بالموت البطيء بعد العذاب المستمر.', 'https://i.ibb.co/bRyghYv8/image.png', 120, 10, 'mystery-horror', '{}'::text[], false, false, 4.4, 120, 2025),
  ('36', 'دهاليز اللا مكان', 'ندا عبدالعزيز', NULL, 'قالوا إنه منزل مهجور. قالوا إنه مجرد مكانٍ قديمٍ نسيه الجميع. لكن المنازل التي تُنسى لا تتنفس… هذا المنزل كان يتنفس. كنا نسمع أنفاسه في الصمت، ونشعر به يراقبنا، لا كغرباء… بل كأطفالٍ عادوا أخيرًا إلى المكان الذي لم يغادروه حقًا.', 'https://i.ibb.co/3m2kLQKT/image.png', 130, 10, 'mystery-horror', ARRAY['drama-romance','sci-fi-history']::text[], false, false, 4.5, 150, 2025),
  ('37', 'مدّ المجهول', 'هبه رزق', NULL, 'في أعماق البحار، حيث يلتقي الضوء بالعتمة، وحيث ترقد الأساطير نائمة في صمت الأزمنة، تبدأ رحلة لا تشبه أي رحلة أخرى. مدّ المجهول ليست مجرد حكاية عن البحر، بل هي غوص في قلب الخوف. تدور أحداث الرواية حول زهرة، مكتشفة بحار شابة، حملت منذ طفولتها هوسًا بسماع القصص الغامضة عن الموج العاتي والكائنات التي لا يعرفها أحد.', 'https://i.ibb.co/5xtJWzdv/image.png', 150, 10, 'sci-fi-history', '{}'::text[], false, false, 4.5, 188, 2025),
  ('38', 'عالم السادية 2', 'محمد أسامة البرقوقي', NULL, 'الشر عاد مرة أخرى. تظهر ليندا فى مفاجأة غير متوقعة. الكل توقع نهاية الشر وانتصار الخير لكن بظهور ليندا تنقلب الأحداث رأسًا على عقب. أحداث السطوة والسيطرة تظهر فى الأحداث. وحلم يقلب موازين الرواية كلها رأسًا على عقب. اقرأ التفاصيل المثيرة وشارك معانا فى صراع أطلانتس الجديد.', 'https://i.ibb.co/DHXJg7kQ/image.png', 100, 8, 'sci-fi-history', '{}'::text[], false, false, 4.3, 84, 2025),
  ('39', 'آثار', 'محمود سمير', NULL, 'كان يظن أن دوره ينتهي عند كشف الآثار… لكنه لم يكن يعلم أن مقبرة الملك تخفي أسرارًا قادرة على ابتلاع روحه. كل نقشة على الجدران تحكي خيانة، وكل حجر يُزيح عنه الغبار يفتح بابًا إلى عهد مظلم من السحر والدماء. وحين انجرف عبر فجوة الزمن، وجد نفسه بين خيارين: إنقاذ ملك خان الجميع… أو مواجهة لعنة ملوك الجن.', 'https://i.ibb.co/n8w1C70V/image.png', 100, 7, 'sci-fi-history', '{}'::text[], false, false, 4.4, 104, 2025),
  ('40', 'تاريخ اليهود والحركة الصهيونية', 'ايهاب عجوه', NULL, 'إلي كل حر مفكر في العالم من أصحاب الديانات السماوية يحمل بداخله الروح السمحة، والصفاء، والعقل المفكر غير المنساق ذو تفكير سليم. هذا الكتاب يوضح الفكر بين اليهودي صاحب العقيدة، واليهودي صاحب الفكر الصهيوني الاستيطاني التي تعمل على تحقيق أفكارها الخبيثة الهدامة.', 'https://i.ibb.co/d4w2ttPb/image.png', 100, 7, 'palestine', ARRAY['sci-fi-history']::text[], false, false, 4.5, 86, 2025),
  ('41', 'وبعد ألف عام', 'منة شوكت', NULL, 'لذلك أنا آسف لك جمال، لقد بِتُ تابعاً للكتاب ولا أقوى على مساعدتك أكثر. أخرج سلاحه وأطلق على أمجد لتخترق الطَلقة رأسه ويسقط صريعاً. رواية تاريخية تمزج بين الحرب والجريمة والدراما عبر أجيال وعصور مختلفة، حيث تتشابك المصائر عبر الزمن.', 'https://i.ibb.co/Xrg2sq40/image.png', 200, 10, 'sci-fi-history', ARRAY['crime-action']::text[], false, false, 4.5, 296, 2025),
  ('42', 'مسك الختام في سيرة خير الأنام', 'الشيخ عبدالحميد أنور', NULL, 'بحث في السيرة النبوية جمعته من كتب السيرة المعتمدة لأئمتنا القدامى والمعاصرين بطريقة مبسطة وسلسة عن طريق سؤال وجواب. تحدثنا عن الحياة السياسية والدينية والاجتماعية قبل البعثة وبعدها، ثم نشأة النبي وغزواته وحياته مع أصحابه وزوجاته. هاردكفر مقاس A4 طباعة ألوان.', 'https://i.ibb.co/tThnpZD7/image.png', 600, 15, 'religious', ARRAY['self-help-psychology']::text[], false, false, 4.8, 561, 2025),
  ('43', 'الجامع الصحيح من وصايا وأقوال الأنبياء والصالحين على فراش الموت', 'د. محمود رضوان', NULL, 'جمعت فيه الوصايا النافعة والكلمات الجامعة والمواعظ الباقية التي قالها الأنبياء والعلماء والصالحون في آخر لحظات حياتهم. يشتمل الكتاب على ثلاثة أبواب بدءًا بالأنبياء والرسل وختمًا بوصايا نبينا محمد ثم الخلفاء الراشدين والصحابة والعلماء والصالحين. هاردكفر مقاس B5 ورق أبيض.', 'https://i.ibb.co/qMxv12sZ/image.png', 300, 12, 'religious', ARRAY['self-help-psychology']::text[], false, false, 4.7, 376, 2025),
  ('44', 'بعض من أقوال الإمام ابن القيم بن جوزية رحمه الله', 'د. ماهينور سيد مرسي', NULL, 'يقدم هذا الكتاب رحلة تأملية فريدة في كنوز الحكمة المستخلصة من أقوال الإمام ابن قيم الجوزية. ارتكز العمل على مجموعة مختارة من أعمق عباراته التي تمس قضايا الإيمان وتزكية النفس وعلاج أمراض القلوب، مع شرح وافٍ ومُيسّر يربط بين عمق النص القديم وواقع الحياة المعاصرة.', 'https://i.ibb.co/mF8cHBH0/image.png', 100, 10, 'religious', ARRAY['self-help-psychology']::text[], false, false, 4.5, 134, 2025),
  ('45', 'فتنة السراء وأول أشراط الساعة الكبرى', 'ناصر بن حسن', NULL, 'يتناول هذا الكتاب الحديث حول بعض الفتن والأحداث وعلامات الساعة بأسلوب جديد وفهم جديد ورؤية مستنيرة. يشتمل على ثلاثة أبواب: الأول يتناول بعض الفتن والأحداث التي وقعت في تاريخ الأمة، والثاني الفتن الثلاث الكبرى، والثالث علامات الساعة الصغرى والكبرى.', 'https://i.ibb.co/0jp0VDc2/image.png', 130, 8, 'religious', '{}'::text[], false, false, 4.5, 170, 2025),
  ('46', 'خروج بني إسرائيل', 'نجاح دياب', NULL, 'دخول وخروج بني إسرائيل في مصر من عهد سيدنا موسى عليه السلام وماذا حدث في عهده وعندما انتشرت ذرية آدم في بقاع الأرض وطالت عليهم المدة، وأخذت المعاصي تزحف لنفوسهم وتتغلغل فيها، واستحوذ إبليس على عقولهم.', 'https://i.ibb.co/DD1rMpDX/image.png', 100, 8, 'religious', '{}'::text[], false, false, 4.4, 120, 2025),
  ('47', 'طفل بلا وطن', 'محمود سمير', NULL, 'خالد... لم يكن مجرد طفل. كان صرخة في وجه النسيان. بعد نجاته من مذبحة محاها الإعلام وغيبها الضمير العالمي، يتحول الطفل الفلسطيني خالد إلى رمز عالمي للكرامة والمقاومة. تنتقل حكايته من خيمة لاجئين إلى منابر الأمم، من أحضان أمهات الثكالى إلى دهاليز المخابرات.', 'https://i.ibb.co/5mZFTww/image.png', 130, 10, 'palestine', '{}'::text[], false, false, 4.6, 165, 2025),
  ('48', 'ملف رقم ١١٧', 'جنى هشام', NULL, 'في أحد الأرشيفات القديمة، يعثر عبدالرحمن، الموظف البسيط، على ملف يحمل صورته وتفاصيل دقيقة عن حياته، لكن الأكثر رعبًا… أن الملف يحتوي على تاريخ وفاته، الذي لم يتبقَ عليه سوى أيام قليلة! بين محاولاته للهروب من المصير المكتوب، وظهور ظلال غامضة تراقبه، يكتشف أن القصة أكبر مما يتخيل.', 'https://i.ibb.co/hxC60Pfs/image.png', 100, 10, 'crime-action', ARRAY['mystery-horror']::text[], false, false, 4.5, 100, 2025),
  ('49', 'أن تكون أو لا تكون.. حبيبي', 'رنا هشام', NULL, 'لم تكن الحكاية عن حبٍ عادي، ولا عن قلبٍ اختار طريقه بسهولة. كانت عن شخصٍ وجد نفسه واقفًا بين احتمالين، كلاهما مؤلم، وكلاهما صادق. كل خطوة للأمام كانت تعني خسارة شيءٍ ما، وكل تراجع كان خيانة للنفس. وفي اللحظة التي ظنّ فيها أن الهروب هو النجاة، اكتشف أن المواجهة وحدها هي الحقيقة. لأن الحب لا يُقاس بما نتمناه، بل بما نقدر على تحمّله. وهنا فقط… يصبح السؤال الحقيقي: أن تكون كما يريد قلبك، أم لا تكون إلا كما يسمح لك عقلك؟', 'https://i.ibb.co/DPyk088Y/image.png', 100, 8, 'drama-romance', '{}'::text[], false, false, 4.5, 100, 2025),
  ('50', 'ممرات معتمة', 'مروى باني', 'أحمد منصور', 'قلبان لا يؤمنان بالحب يلتقيان صدفة، في لحظة تغيّر كل شيء. آمنة تحمل ندبة خيانة لم تلتئم، ويوسف يعيش بفقدانٍ قديم جعله يخشى التعلّق. بين اعترافات صادقة وخطوات مترددة، تبدأ علاقة تنمو على مهل… لكن الماضي لا يبقى صامتًا. حبيب قديم يعود طالبًا الغفران، وصديقة تخفي مشاعر معقّدة، والشكّ يتسلل إلى قلب كان يتعلّم الثقة من جديد.', 'https://i.ibb.co/TMVsrN2P/image.png', 120, 9, 'drama-romance', '{}'::text[], false, false, 4.4, 128, 2025),
  ('51', 'اميرة الملائكة', 'مروه فؤاد', NULL, 'تحكي عن فتاه تُولد من بذور ملائكية ومواصفات خاصة تجعل كل من ينظر لها يحبها ويشعر بالحظ والسعادة لوجودها معه وتجد صراع بين ابراهيم ولؤي في حبهم لها والفت صديقتها التي لقت مصيرها ويتحول الشيطان الي انسان بسبب الحب ولكن تجد ان الزوهرين لمكان لهم في ظل تلك الصراعات الدنيوية.', 'https://i.ibb.co/23RYFYFX/image.png', 100, 8, 'drama-romance', ARRAY['self-help-psychology']::text[], false, false, 4.3, 86, 2025),
  ('52', 'بين المطرقة والسندان', 'مروة محمود نورالدين', NULL, 'الكتاب مش مجرّد عرض وقائع، لكنه محاولة لفهم الجريمة من منظور إنساني، اجتماعي، ونفسي. يمتزج فيه بين السرد الواقعي، والتحليل، والرسائل التوعوية. الهدف مش بس إننا نحكي حكايات الضحايا، لكن إننا نوصل رسائل حقيقية عن طريق الخوف، والسكوت، والمجتمع، والعدل.', 'https://i.ibb.co/Lz6zn1Nz/image.png', 100, 10, 'crime-action', '{}'::text[], false, false, 4.4, 92, 2025),
  ('53', 'الطابق السابع بعد المائة', 'محمد خلاف', NULL, 'في عمارة عتيقة... لكل طابق حكاية، ولكل شقة عمر مكتوم. من البدروم حتى الطابق الأخير، نسير بين حكايات أناس لا يسكنون الجدران فقط، بل تسكنهم الحياة بكل ما فيها من وجع وأمل، من انكسار وحُلم.', 'https://i.ibb.co/C38cvZgq/image.png', 120, 8, 'drama-romance', '{}'::text[], false, false, 4.5, 150, 2025),
  ('54', 'بنت الناطور', 'رجاء حمدان', NULL, 'ابنة الناطور… فتاة جميلة، طموحة، تحمل في قلبها كبرياءً لا يُقهَر وأحلامًا تتجاوز حدود عالمها الضيق. نشأت بين جدران الفيلا التي يعمل فيها والدها، مراقبة الحياة بصمت، وتحلم بمستقبل أكبر من قيود الواقع.', 'https://i.ibb.co/9m0158dB/image.png', 200, 10, 'crime-action', '{}'::text[], false, false, 4.6, 311, 2025),
  ('55', '1910 "لعنة الدم"', 'كريم سعيد', NULL, 'سنذهب معاً الى التاريخ القديم الذي روى بعض الأحداث المثيرة للغاية في زمن الإحتلال البريطانى في فترة 1910. فى مدينة تغلي تحت رماد الإمبراطوريات، فى وقت تباع فيه الأرواح كما تباع أرغفة الخبز، كان الصراع بينهم طائل ولن ينتهي إلا بالقتل.', 'https://i.ibb.co/d0d7jkbM/image.png', 200, 10, 'crime-action', ARRAY['sci-fi-history']::text[], false, false, 4.5, 246, 2025),
  ('56', 'غرفة ٢٢٢', 'أدهم محمد', NULL, 'داخل فندق اوركيدا عُثر على الدكتور رائف مقتولًا داخل الغرفة 222.

الباب مغلق من الداخل بالمفتاح.

النافذة مغلقة بإحكام.

الساعة متوقفة عند 02:22.

المرآة محطمة بالكامل.

كوب شاي على الطاولة يحتوي على بقايا مهدئ.

على الحائط مكتوب بدم الضحية:

"التجربة بدأت منذ زمن".

من القاتل؟', 'https://i.ibb.co/Q7M7ZBPB/image.png', 100, 10, 'crime-action', ARRAY['mystery-horror']::text[], false, false, 4.5, 100, 2025),
  ('57', 'قاعة اللا موتى', 'محمود عليوه', NULL, 'تجارب علمية يجريها الدكتور ثروت القادم من الخارج. لاختبار إرجاع الإنسان إلى الماضي والتنقل بين الذكريات. يعمل طبيبًا نفسيًا في العلن. لكنه في الخفاء يجري تجارب غير أخلاقية على البشر، يدخل في صراع مع عمار صاحب المزرعة السمكية. بعد إن كانت زوجته ضحية؛ لهذه التجارب. يكتشف عمار أن صديقه السابق متورط. وأن الطبيب يستخدمه كفأر تجارب؛ فيعيش صراعًا نفسيًا يجعله مدمنًا على عقار الطبيب متنقلاً بين مشاهد الماضي، حتى يقترب من الجنون، كن بحثه عن الحقيقة يثبت نجاح التجربة، فيقرر الانتقام داخل قاعة اللاموتي؛ حيث الداخل مفقود، والخارج مولود.', 'https://i.ibb.co/JWHFfPgX/image.png', 150, 10, 'mystery-horror', ARRAY['crime-action']::text[], false, false, 4.5, 188, 2025),
  ('58', 'كانت هنا ولا تزال', 'ريهام عبد العظيم', NULL, '" أنا لم أمت... لقد قتلوني"

ليان لم تعد هنا بجسدها ولكن ظلت روحها معلقة حتى أخدت حقها

عندما تبدأ الرسائل المجهولة في الظهور… وعندما تعود الأصوات التي خفتت…

يكتشف الجميع أن الحكاية لم تنتهِ.

فمن كانت؟ ولماذا ما زالت هنا؟

وإلى أي حدّ يمكن أن يُغيّر وجود شخصٍ واحد مصائر آخرين؟', 'https://i.ibb.co/pBmZFTkZ/image.png', 100, 10, 'crime-action', ARRAY['mystery-horror']::text[], false, false, 4.5, 100, 2025),
  ('60', 'ترياق الوّجد', 'محمد روبيو', NULL, 'متى يكون للحب حدود؟ ومتى يكون الحب مقترنا بعمر محدد؟ في مكان بعيد وفي قرية مهملة حيث يولد الحبُ صدفة بين أروقتها ويكبر، عندما يكون ذلك الحب طاهرا مقدسا وفي أول لقاء، فيليه اعتراف قد شغل البال مأله فهل يقترب أم يبتعد هل تكون هنالك فرصة ليكتمل ذلك لإحساس إن لم تعد تروي عطش الحب تلك النظرات؟ فإن اكتمل فهل يدوم؟ أو تراها القلوب تحب بوفاء، تمشي في درب من الحاضرين ولا ترى إلا غائبا عنها، خيبة فانكسار فحزن فأمل فنهوض من تحت الأنقاض، يحيى الحب في كلمة تظن بأنه مات واندثر، ترياق الوجد هو حب لا يعرف الحدود ليس مجرد كلمة

حب لا يهزه إلا كبرياء وعزة نفس تمشي في العروق أكثر من الدم..', 'https://i.ibb.co/v6p1XTk6/image.png', 160, 8, 'drama-romance', '{}'::text[], false, false, 4.5, 186, 2026),
  ('61', 'أحلام شائكة', 'جمال تمراز', NULL, 'أحلام شائكة رواية تجسّد حكاية عائلة فلسطينية تعيش بين أتون الحرب وتقلبات المصير، حيث تتحول الحياة اليومية إلى اختبار قاسٍ للصبر والإيمان.

في قلب الأحداث يقف الدكتور سمير، الطبيب الذي يصرّ على أداء رسالته رغم الخطر، وتواجه زوجته فقدًا موجعًا خلال رحلة نزوح مريرة، بينما تسطر حليمة وابنتها عائشة أروع صور التضحية والكفاح، وهما تصارعان قسوة الواقع وتحملان أعباء الحياة بصبرٍ يليق بالمناضلين في صمت.

ومع تصاعد المأساة، تتكشف معادن البشر، ويصبح الصمود خيارًا لا بديل عنه.

لكن وسط الركام، يظل بصيص الأمل حاضرًا، كزهرة تنبت بين الأشواك، تؤكد أن الحياة — مهما اشتد الألم — قادرة على النهوض من جديد.', 'https://i.ibb.co/BKFdKkWf/image.png', 200, 10, 'palestine', ARRAY['crime-action']::text[], false, false, 4.6, 300, 2026),
  ('62', 'رائحة الغدر', 'جمال تمراز', NULL, 'في حارةٍ شعبية هادئة، حيث تبدو الحياة بسيطة والوجوه مألوفة، تقع جريمة تقلب كل شيء رأسًا على عقب.

ومع بدء التحقيقات، تتكشف أسرار دفنت طويلًا خلف الأبواب المغلقة، وتصبح الحقيقة أكثر تعقيدًا مما يظنه الجميع.

في «رائحة الغدر» تتشابك المصائر، وتتبدل الوجوه، وتتحول الثقة إلى شك، بينما يقترب الجميع خطوة بعد أخرى من سرٍ خطير…

سرّ قد يكون أقرب مما يتخيلون.', 'https://i.ibb.co/FqVL3kjZ/image.png', 200, 10, 'crime-action', '{}'::text[], false, false, 4.5, 260, 2026),
  ('63', 'الإدارة الحديثة في عصر الذكاء الإصطناعي', 'وليد فوزي', NULL, 'الإدارة الحديثة في عصر الذكاء الاصطناعي

يقدم الكتاب رؤيةً شاملةً عن كيفية تحويل الذكاء الاصطناعي من الممارسات الإدارية التقليدية إلى أنظمة ذكية تعزز الكفاءة واتخاذ القرار.

يستعرض الكتاب تطور الذكاء الاصطناعي وتطبيقاته المعاصرة في إدارة المنظمات، مع التركيز على دوره المحوري في إدارة الموارد البشرية بدءًا من التوظيف الذكي وتحليل البيانات وصولًا إلى تطوير الموظفين وتقييم أدائهم.

يتناول أيضًا كيفية تحسين العمليات التشغيلية عبر الأتمتة والتنبؤ بالاتجاهات وتحسين جودة المنتجات والخدمات.

يناقش الكتاب دور الذكاء الاصطناعي في دعم القرارات الإدارية من خلال تحليل البيانات الضخمة واستخلاص الأنماط، إضافةً إلى التخطيط الاستراتيجي والتنبؤ بالمستقبل.

لا يغفل الكتاب التحديات المصاحبة لهذا التحول، خاصةً الأخلاقية والقانونية منها، وتأثير الذكاء الاصطناعي على سوق العمل والوظائف التقليدية.

يختتم الكتاب باستشراف الاتجاهات المستقبلية للإدارة الذكية في ظل التطورات المتسارعة للذكاء الاصطناعي، مؤكدًا أن المؤسسات التي تتبنى هذه التقنيات ستكون الأكثر قدرة على المنافسة والبقاء.', 'https://i.ibb.co/6RfVXYrm/image.png', 120, 10, 'self-help-psychology', '{}'::text[], false, false, 4.5, 118, 2026)
